#!/usr/bin/env bash
# Runs INSIDE the swerve Arch sliver: monster-guard admission gated on the PARIS
# quality probe, then runs the admitted model under a capability lease.
export PATH=/usr/local/bin:/usr/bin:/bin HOME=/root MONSTER_GUARD_HOME=/root/.mg
echo "=== GOLDEN STAR inside a swerve sliver on the Rabbit R1 ==="
echo "host: $(uname -m) / $(grep -m1 PRETTY_NAME /etc/os-release | cut -d= -f2)"
monster-guard delegate qwen-0.5b-agent net,fs --ttl 3600 --qspec /root/paris.json 2>&1 | tail -4
monster-guard run --name qwen-0.5b-agent --caps net,fs --lease 60 --max 120 -- \
  /usr/local/bin/paris-probe-rknot --dense /root/qwen05-dense.knot --dense-only \
  --tokens 785,6722,315,9625,374 --expected 12095 --top-k 3 2>&1 \
  | grep -iE "unsigned|PASS|argmax|matches|lease" | head -6
echo "=== sliver done ==="
